112	unsigned int GetLegacySigOpCount(const CTransaction& tx)
113	{
114	    unsigned int nSigOps = 0;
115	    for (const auto& txin : tx.vin)
116	    {
117	        nSigOps += txin.scriptSig.GetSigOpCount(false);
118	    }
119	    for (const auto& txout : tx.vout)
120	    {
121	        nSigOps += txout.scriptPubKey.GetSigOpCount(false);
122	    }
123	    return nSigOps;
124	}
