1994	void Chainstate::InvalidBlockFound(CBlockIndex* pindex, const BlockValidationState& state)
1995	{
1996	    AssertLockHeld(cs_main);
1997	    if (state.GetResult() != BlockValidationResult::BLOCK_MUTATED) {
1998	        pindex->nStatus |= BLOCK_FAILED_VALID;
